interface RateLimitConfig {
  tokensPerSecond: number;  // Rate of token refill
  burstCapacity: number;    // Max tokens that can be stored
}

interface UserBucket {
  tokens: number;
  lastRefillTime: number;
}

export class RateLimiter {
  private config: RateLimitConfig;
  private buckets: Map<string, UserBucket> = new Map();

  constructor(tokensPerSecond: number, burstCapacity: number) {
    this.config = { tokensPerSecond, burstCapacity };
  }

  isAllowed(userId: string, tokensNeeded: number = 1): boolean {
    const now = Date.now();
    let bucket = this.buckets.get(userId);

    if (!bucket) {
      bucket = {
        tokens: this.config.burstCapacity,
        lastRefillTime: now
      };
      this.buckets.set(userId, bucket);
    }

    // Refill tokens based on time elapsed
    const timePassed = (now - bucket.lastRefillTime) / 1000; // Convert to seconds
    const tokensToAdd = timePassed * this.config.tokensPerSecond;
    bucket.tokens = Math.min(
      this.config.burstCapacity,
      bucket.tokens + tokensToAdd
    );
    bucket.lastRefillTime = now;

    // Check if enough tokens available
    if (bucket.tokens >= tokensNeeded) {
      bucket.tokens -= tokensNeeded;
      return true;
    }
    return false;
  }
}
```

